<?php

namespace Database\Seeders;

use App\Models\Question;
use App\Models\Answer;
use Illuminate\Database\Seeder;

class QuestionBankSeeder extends Seeder
{
    public function run(): void
    {
        foreach ($this->data() as $category => $difficulties) {
            foreach ($difficulties as $difficulty => $rows) {
                foreach ($rows as $r) {
                    $question = Question::firstOrCreate(
                        ['content' => $r[0], 'category' => $category],
                        ['difficulty' => $difficulty]
                    );
                    if ($question->wasRecentlyCreated) {
                        Answer::create(['question_id' => $question->id, 'content' => $r[1], 'is_correct' => true]);
                        Answer::create(['question_id' => $question->id, 'content' => $r[2], 'is_correct' => false]);
                        Answer::create(['question_id' => $question->id, 'content' => $r[3], 'is_correct' => false]);
                        Answer::create(['question_id' => $question->id, 'content' => $r[4], 'is_correct' => false]);
                    }
                }
            }
        }
    }

